from string_utils.validation import is_full_string

def test__is_full_string_non_string():
    # Testing non-string inputs which should return False
    non_string_inputs = [None, 9, [], {}, set()]

    results = {str(input): is_full_string(input) for input in non_string_inputs}

    for input_val, output in results.items():
        print(f"Input: {input_val} -> Output: {output}")

from string_utils.validation import is_full_string

def test__is_full_string_with_list_input():
    # Testing with a list input which should raise an InvalidInputError in baseline
    list_input = ['this', 'is', 'a', 'list']

    try:
        list_output = is_full_string(list_input)
        print(f"List input output: {list_output}")
    except Exception as e:
        print(f"List input raised an exception: {e}")
